handleValue = props => {
  let questionnaire = this.state.questionnaire;
  let questions = questionnaire.questions;
  const Index = questions.findIndex(question => question.id === props.id);
  questions[Index] = props;
  questionnaire.questions = questions;
  //Calcul categories values
  let categories = questionnaire.categories;
  categories.map(cat => cat.value = (questions.filter(question => question.categoryId === cat.id).reduce((acc, cur) => ({
    value: acc.value + cur.value
  })).value / questions.filter(question => question.categoryId === cat.id).length).toFixed(2));
  questionnaire.categories = categories;
  this.setState({
    questionnaire: questionnaire
  });
};

